args.script:
using UnityEngine;
using UnityEngine.UI;
using TowerDefense.UI;

var go = UnityEngine.Object.FindObjectOfType<UnityEngine.GameObject>();
// Find the "开始游戏" button
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<RectTransform>();
Transform target = null;
foreach (var t in allTransforms)
{
    if (t != null && t.name == "开始游戏" && t.parent != null && t.parent.name == "ui按钮")
    {
        target = t;
        break;
    }
}

if (target == null)
{
    UnityEngine.Debug.LogError("Could not find '开始游戏' button");
}
else
{
    var buttonGo = target.gameObject;
    // Add StartGameButton component
    var startGame = buttonGo.GetComponent<StartGameButton>();
    if (startGame == null)
    {
        startGame = buttonGo.AddComponent<StartGameButton>();
    }

    // Ensure Button component exists
    var button = buttonGo.GetComponent<Button>();
    if (button == null)
    {
        button = buttonGo.AddComponent<Button>();
    }

    // Wire up onClick event
    button.onClick.RemoveAllListeners();
    button.onClick.AddListener(startGame.OnStartGameClicked);

    UnityEngine.Debug.Log($"StartGameButton attached to '{buttonGo.name}', onClick wired up. Scene name: GameScene");
}

