args.script:
using UnityEditor;
using UnityEngine;
using UnityEngine.UI;
using TowerDefense.UI;

// Find the "开始游戏" button
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<RectTransform>();
Transform target = null;
foreach (var t in allTransforms)
{
    if (t != null && t.name == "开始游戏" && t.parent != null && t.parent.name == "ui按钮")
    {
        target = t;
        break;
    }
}

if (target == null)
{
    UnityEngine.Debug.LogError("Could not find '开始游戏' button");
}
else
{
    var buttonGo = target.gameObject;
    var button = buttonGo.GetComponent<UnityEngine.UI.Button>();
    var startGame = buttonGo.GetComponent<TowerDefense.UI.StartGameButton>();

    if (button == null || startGame == null)
    {
        UnityEngine.Debug.LogError("Missing Button or StartGameButton component");
    }
    else
    {
        // Clear any runtime listeners
        button.onClick.RemoveAllListeners();

        // Add persistent (serialized) listener via Undo to support serialization
        UnityEditor.Events.UnityEventTools.AddPersistentListener(button.onClick, startGame.OnStartGameClicked);

        // Mark scene dirty so it gets saved
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(buttonGo.scene);

        UnityEngine.Debug.Log($"Persistent onClick event bound for '{buttonGo.name}' -> StartGameButton.OnStartGameClicked()");
    }
}

