    public class WaveManager : MonoBehaviour
    {
        public static WaveManager Instance { get; private set; }

        [Header("Settings")]
        [SerializeField] private EnemySpawner _enemySpawner;
        [SerializeField] private float _waveDelay = 5f;
        [SerializeField] private int _totalWaves = 5;
        [SerializeField] private int _baseEnemyCount = 5;
        [SerializeField] private int _enemyIncreasePerWave = 2;

        [Header("Wave Data (Optional)")]
        [Tooltip("如果设置了这个数组，将使用这里的配置而不是动态生成")]
        [SerializeField] private WaveData[] _waveDatas;

        [Header("Enemy Data")]
        [Tooltip("所有可用的敌人数据（飞机、骷髅等）")]
        [SerializeField] private EnemyData[] _enemyDatas;

        private EnemyData _defaultEnemyData;

        [Header("UI")]
        [SerializeField] private Text _waveText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Text _waveAnnounceText;
        [SerializeField] private float _announceDuration = 2f;

        private int _currentWaveIndex = 0;
        private float _waveTimer = 0f;
        private bool _isWaveActive = false;
        private bool _isWaveTransition = false;

        public int CurrentWave => _currentWaveIndex;
        public int TotalWaves => _totalWaves;
        public bool IsWaveActive => _isWaveActive;

        private void Awake()
        {
            if (Instance == null)
            {
                Instance = this;
            }
            else
            {
                Destroy(gameObject);
            }
        }

        private void Start()
        {
            LoadEnemyData();
            UpdateWaveUI();

            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }

            EventBus.Subscribe<GameStartEvent>(OnGameStart);
        }

        private void LoadEnemyData()
        {
            // 如果在 Inspector 中设置了敌人数据数组，直接使用
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                Debug.Log($"已加载 {_enemyDatas.Length} 个敌人数据");
                foreach (var enemy in _enemyDatas)
                {
                    Debug.Log($"  - {enemy.enemyName}");
                }
                // 使用第一个作为默认
                _defaultEnemyData = _enemyDatas[0];
                return;
            }

            // 否则尝试从 Resources 加载
            _defaultEnemyData = Resources.Load<EnemyData>("Data/EnemyData");
            if (_defaultEnemyData == null)
            {
                Debug.LogError("Failed to load EnemyData from Resources/Data/EnemyData");
            }
        }

        private void OnDestroy()
        {
            EventBus.Unsubscribe<GameStartEvent>(OnGameStart);
        }

        private void OnGameStart(GameStartEvent e)
        {
            ForceStartWave();
        }

        private void Update()
        {
            if (_isWaveTransition && !_isWaveActive)
            {
                _waveTimer += Time.deltaTime;

                float remainingTime = _waveDelay - _waveTimer;

                if (remainingTime > 0)
                {
                    UpdateWaveCountdown((int)Mathf.CeilToInt(remainingTime));
                }

                if (remainingTime % 1f < 0.05f)
                {
                    Debug.Log($"倒计时更新: timer={_waveTimer:F1}/{_waveDelay}, 剩余={remainingTime:F1}s, transition={_isWaveTransition}, active={_isWaveActive}");
                }

                if (_waveTimer >= _waveDelay)
                {
                    Debug.Log($"✅ 倒计时结束, 准备开始下一波!");
                    _waveTimer = 0f;
                    HideWaveCountdown();
                    StartNextWave();
                }
            }

            UpdateEnemyCountDisplay();
        }

        private void UpdateWaveCountdown(int seconds)
        {
            if (_waveAnnounceText != null)
            {
                int nextWave = _currentWaveIndex + 1;
                _waveAnnounceText.text = $"第 {nextWave} 波 {seconds} 秒后出现！";
                _waveAnnounceText.gameObject.SetActive(true);
            }
        }

        private void HideWaveCountdown()
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private void UpdateEnemyCountDisplay()
        {
            if (_enemyCountText != null)
            {
                // 用 EnemySpawner 追踪的波次剩余敌人（出生总数 - 死亡数）
                _enemyCountText.text = $"剩余敌人:{TowerDefense.Enemy.EnemySpawner.RemainingEnemies}";
            }
        }

        public void StartNextWave()
        {
            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log("All waves completed!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
                return;
            }

            // 先增加波次索引
            _currentWaveIndex++;

            WaveData waveData = GetWaveData();
            if (waveData == null)
            {
                Debug.LogError("Failed to get wave data!");
                return;
            }

            _enemySpawner.StartWave(waveData);

            _isWaveActive = true;
            _isWaveTransition = false;

            if (GameManager.Instance != null)
            {
                GameManager.Instance.SetCurrentWave(_currentWaveIndex);
            }

            EventBus.Publish(new WaveStartEvent { WaveIndex = _currentWaveIndex });

            UpdateWaveUI();
            StartCoroutine(ShowWaveAnnouncement(_currentWaveIndex));
            Debug.Log($"Starting wave {_currentWaveIndex}");
        }

        private IEnumerator ShowWaveAnnouncement(int waveNumber)
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.text = $"第 {waveNumber} 波开始出怪！";
                _waveAnnounceText.gameObject.SetActive(true);

                Debug.Log($"📢 {_waveAnnounceText.text}");

                yield return new WaitForSeconds(_announceDuration);

                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private WaveData GetWaveData()
        {
            // 如果用户设置了 WaveData 数组，使用它
            if (_waveDatas != null && _waveDatas.Length > 0)
            {
                int index = _currentWaveIndex - 1;
                if (index >= 0 && index < _waveDatas.Length)
                {
                    Debug.Log($"使用配置的 WaveData: 波次 {_currentWaveIndex}");
                    return _waveDatas[index];
                }
            }

            // 否则动态生成
            if (_defaultEnemyData == null && (_enemyDatas == null || _enemyDatas.Length == 0))
            {
                Debug.LogError("No EnemyData available! Cannot create wave data.");
                return null;
            }

            Debug.Log($"动态生成 WaveData: 波次 {_currentWaveIndex}");
            return CreateWaveData();
        }

        private WaveData CreateWaveData()
        {
            WaveData waveData = ScriptableObject.CreateInstance<WaveData>();
            waveData.waveNumber = _currentWaveIndex;
            waveData.spawnInterval = Mathf.Max(0.5f, 1.5f - (_currentWaveIndex - 1) * 0.1f);
            waveData.enemies = new List<WaveData.WaveEnemy>();

            int totalEnemies = _baseEnemyCount + (_currentWaveIndex - 1) * _enemyIncreasePerWave;

            // 使用多个敌人数据
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                // 随机选择敌人
                for (int i = 0; i < _enemyDatas.Length; i++)
                {
                    int enemyCount = totalEnemies / _enemyDatas.Length;
                    if (i == 0)
                    {
                        enemyCount += totalEnemies % _enemyDatas.Length;
                    }

                    if (enemyCount > 0)
                    {
                        waveData.enemies.Add(new WaveData.WaveEnemy
                        {
                            enemyData = _enemyDatas[i],
                            count = enemyCount,
                            spawnDelay = 0,
                            spawnPoint = "MainPath"
                        });

                        Debug.Log($"波次 {_currentWaveIndex} 添加 {enemyCount} 个 {_enemyDatas[i].enemyName}");
                    }
                }
            }
            else
            {
                // 只有一个敌人数据时使用旧方法
                waveData.enemies.Add(new WaveData.WaveEnemy
                {
                    enemyData = _defaultEnemyData,
                    count = totalEnemies,
                    spawnDelay = 0,
                    spawnPoint = "MainPath"
                });
            }

            return waveData;
        }

        public void OnWaveComplete()
        {
            _isWaveActive = false;

            Debug.Log($"波次 {_currentWaveIndex}/{_totalWaves} 完成!");
            EventBus.Publish(new WaveEndEvent { WaveIndex = _currentWaveIndex });

            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log($"全部波次完成!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
            }
            else
            {
                _isWaveTransition = true;
                _waveTimer = 0f;
            }

            UpdateWaveUI();
        }

        public void StartWaveManually(int waveIndex)
        {
            if (waveIndex >= 0 && waveIndex < _totalWaves)
            {
                _currentWaveIndex = waveIndex;
                StartNextWave();
            }
        }

        public void SkipToNextWave()
        {
            if (!_isWaveActive && _currentWaveIndex < _totalWaves)
            {
                StartNextWave();
            }
        }

        public void ForceStartWave()
        {
            if (!_isWaveActive)
            {
                _isWaveTransition = false;
                _waveTimer = 0f;
                StartNextWave();
            }
        }

        private void UpdateWaveUI()
        {
            if (_waveText != null)
            {
                _waveText.text = $"波次:{_currentWaveIndex}/{_totalWaves}";
            }

            UpdateEnemyCountDisplay();
        }

        public void Reset()
        {
            _currentWaveIndex = 0;
            _waveTimer = 0f;
            _isWaveActive = false;
            _isWaveTransition = false;
            UpdateWaveUI();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Core
{
    public static class EventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                (_events[eventType] as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region Event Data Structures

    public struct GameStartEvent { }
    public struct GamePauseEvent { public bool IsPaused; }
    public struct GameOverEvent { public bool IsVictory; }
    public struct WaveStartEvent { public int WaveIndex; }
    public struct WaveEndEvent { public int WaveIndex; }
    public struct EnemySpawnEvent { public GameObject Enemy; }
    public struct EnemyDeathEvent { public GameObject Enemy; public int Reward; }
    public struct EnemyReachEndEvent { public GameObject Enemy; public int Damage; }
    public struct TowerPlacedEvent { public GameObject Tower; public int Cost; }
    public struct TowerUpgradedEvent { public GameObject Tower; public int Level; }
    public struct TowerSoldEvent { public GameObject Tower; public int Refund; }
    public struct GoldChangedEvent { public int CurrentGold; public int Change; }
    public struct LifeChangedEvent { public int CurrentLife; public int Change; }
    public struct SkillUsedEvent { public string SkillName; }

    #endregion
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class Projectile : MonoBehaviour
    {
        [Header("Movement Settings")]
        [SerializeField] private float _speed = 10f;
        [SerializeField] private float _homingStrength = 5f;

        [Header("Pierce Settings (Sword Tower)")]
        [SerializeField] private int _maxPierceCount = 3;
        [SerializeField] private float _maxLifetime = 3f;
        [SerializeField] private float _hitCooldown = 0.2f;

        [Header("Impact Settings")]
        [SerializeField] private GameObject _impactEffect;
        [SerializeField] private float _impactDuration = 1f;

        [Header("Debug")]
        [SerializeField] private bool _showDebugLogs = false;

        private Enemy.Enemy _target;
        private float _damage;
        private DamageType _damageType;
        private float _splashRadius = 0f;
        private bool _hasHit = false;

        private bool _isPierceMode = false;
        private List<Enemy.Enemy> _hitEnemies = new List<Enemy.Enemy>();
        private int _currentPierceCount = 0;
        private Vector3 _moveDirection;
        private float _lifetimeTimer = 0f;
        private float _lastHitTime = 0f;

        public void Initialize(Enemy.Enemy target, float damage, DamageType damageType, float splashRadius = 0f, int pierceCount = 0)
        {
            _target = target;
            _damage = damage;
            _damageType = damageType;
            _splashRadius = splashRadius;
            _hasHit = false;

            _isPierceMode = pierceCount > 0;

            if (_isPierceMode)
            {
                _maxPierceCount = pierceCount;
                if (target != null)
                {
                    _moveDirection = (target.transform.position - transform.position).normalized;
                }
                else
                {
                    _moveDirection = transform.up;
                }

                float angle = Mathf.Atan2(_moveDirection.y, _moveDirection.x) * Mathf.Rad2Deg - 90f;
                transform.rotation = Quaternion.AngleAxis(angle, Vector3.forward);

                if (_showDebugLogs)
                {
                    Debug.Log($"⚔️ 穿透模式: maxPierce={_maxPierceCount}, dir=({_moveDirection.x:F2},{_moveDirection.y:F2})");
                }
            }

            _hitEnemies.Clear();
            _currentPierceCount = 0;
            _lifetimeTimer = 0f;
            _lastHitTime = 0f;
        }

        private void Update()
        {
            if (_isPierceMode)
            {
                UpdatePierceMovement();
                return;
            }

            if (_target == null || _target.IsDead)
            {
                FindNewTarget();
                if (_target == null)
                {
                    Destroy(gameObject);
                    return;
                }
            }

            MoveTowardsTarget();
        }

        private void UpdatePierceMovement()
        {
            _lifetimeTimer += Time.deltaTime;

            if (_lifetimeTimer >= _maxLifetime || _currentPierceCount >= _maxPierceCount)
            {
                if (_showDebugLogs)
                {
                    Debug.Log($"穿透结束: life={_lifetimeTimer:F1}s, hits={_currentPierceCount}");
                }
                DestroyProjectile();
                return;
            }

            float actualSpeed = _speed * 100f;
            transform.position += _moveDirection * actualSpeed * Time.deltaTime;

            CheckPierceHits();
        }

        private void CheckPierceHits()
        {
            if (Time.time - _lastHitTime < _hitCooldown) return;

            float hitRange = 50f;

            Enemy.Enemy[] allEnemies = FindObjectsOfType<Enemy.Enemy>();
            List<Enemy.Enemy> enemiesInRange = new List<Enemy.Enemy>();

            foreach (var enemy in allEnemies)
            {
                if (enemy == null || enemy.IsDead) continue;

                float dist = Vector3.Distance(transform.position, enemy.transform.position);
                if (dist <= hitRange)
                {
                    enemiesInRange.Add(enemy);
                }
            }

            if (_showDebugLogs && enemiesInRange.Count > 0)
            {
                Debug.Log($"范围内有 {enemiesInRange.Count} 个敌人, 已击中: {_hitEnemies.Count}");
            }

            foreach (var enemy in enemiesInRange)
            {
                if (_hitEnemies.Contains(enemy)) continue;

                if (_showDebugLogs)
                {
                    Debug.Log($"💥 击中敌人! {enemy.name}, 第 {_currentPierceCount + 1}/{_maxPierceCount} 次");
                }

                DealDamageToEnemy(enemy);
                _hitEnemies.Add(enemy);
                _currentPierceCount++;
                _lastHitTime = Time.time;

                PlayImpactEffect();

                if (_currentPierceCount >= _maxPierceCount)
                {
                    DestroyProjectile();
                    return;
                }
            }
        }

        private void MoveTowardsTarget()
        {
            if (_target == null) return;

            Vector3 targetPosition = _target.transform.position;
            Vector3 direction = (targetPosition - transform.position).normalized;

            float actualSpeed = _speed * 100f;
            transform.position += direction * actualSpeed * Time.deltaTime;

            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg - 90f;
            transform.rotation = Quaternion.AngleAxis(angle, Vector3.forward);

            float distance = Vector3.Distance(transform.position, targetPosition);
            if (distance <= 30f)
            {
                HitTarget();
            }
        }

        private void FindNewTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner != null)
            {
                _target = spawner.GetClosestEnemy(transform.position, 500f);
            }
        }

        private void HitTarget()
        {
            if (_hasHit) return;
            _hasHit = true;

            if (_splashRadius > 0)
            {
                DealSplashDamage();
            }
            else
            {
                DealSingleTargetDamage();
            }

            PlayImpactEffect();
            Destroy(gameObject);
        }

        private void DealSingleTargetDamage()
        {
            if (_target != null && !_target.IsDead)
            {
                _target.Health.TakeDamage(Mathf.RoundToInt(_damage), _damageType);
            }
        }

        private void DealDamageToEnemy(Enemy.Enemy enemy)
        {
            if (enemy != null && !enemy.IsDead)
            {
                enemy.Health.TakeDamage(Mathf.RoundToInt(_damage), _damageType);
            }
        }

        private void DealSplashDamage()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInSplash = spawner.GetEnemiesInRange(transform.position, _splashRadius);

            foreach (var enemy in enemiesInSplash)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    float distance = Vector3.Distance(transform.position, enemy.transform.position);
                    float damageMultiplier = 1f - (distance / _splashRadius) * 0.5f;
                    int damage = Mathf.RoundToInt(_damage * damageMultiplier);
                    enemy.Health.TakeDamage(damage, _damageType);
                }
            }
        }

        private void PlayImpactEffect()
        {
            if (_impactEffect != null)
            {
                GameObject effect = Instantiate(_impactEffect, transform.position, Quaternion.identity);
                Destroy(effect, _impactDuration);
            }
        }

        private void DestroyProjectile()
        {
            _hasHit = true;
            Destroy(gameObject);
        }

        private void OnTriggerEnter2D(Collider2D other)
        {
            if (_isPierceMode) return;

            Enemy.Enemy enemy = other.GetComponent<Enemy.Enemy>();
            if (enemy != null && enemy == _target)
            {
                HitTarget();
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Hero
{
    public enum HeroState
    {
        Idle,
        Moving,
        Attacking,
        UsingSkill,
        Dead
    }

    public class Hero : MonoBehaviour
    {
        [Header("Data")]
        [SerializeField] private HeroData _heroData;

        [Header("Components")]
        [SerializeField] private Animator _animator;
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Transform _healthBarAnchor;

        [Header("Movement")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _arrivalThreshold = 0.2f;

        private HeroState _currentState = HeroState.Idle;
        private HeroData.HeroStats _currentStats;
        private float _currentHealth;
        private int _currentLevel = 1;
        private float _currentExp = 0f;
        private float _expToNextLevel = 100f;

        private Enemy.Enemy _currentTarget;
        private Vector3 _targetPosition;
        private bool _isMoving = false;
        private float _attackCooldown = 0f;

        private Dictionary<string, float> _skillCooldowns = new Dictionary<string, float>();

        public HeroData Data => _heroData;
        public HeroState State => _currentState;
        public int CurrentLevel => _currentLevel;
        public float CurrentHealth => _currentHealth;
        public float HealthPercent => _currentHealth / _currentStats.maxHealth;
        public float CurrentExp => _currentExp;
        public float ExpPercent => _currentExp / _expToNextLevel;
        public bool IsDead => _currentState == HeroState.Dead;

        public System.Action<Hero> OnLevelUp;
        public System.Action<Hero> OnDeath;
        public System.Action<float> OnHealthChanged;
        public System.Action<float> OnExpChanged;
        public System.Action<string> OnSkillUsed;
        public System.Action<string> OnSkillReady;

        private void Awake()
        {
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
            if (_spriteRenderer == null) _spriteRenderer = GetComponentInChildren<SpriteRenderer>();
        }

        public void Initialize(HeroData data)
        {
            _heroData = data;
            _currentStats = data.baseStats;
            _currentHealth = _currentStats.maxHealth;
            _currentLevel = 1;
            _currentExp = 0f;
            _currentState = HeroState.Idle;

            foreach (var skill in _heroData.skills)
            {
                _skillCooldowns[skill.skillName] = 0f;
            }
        }

        private void Update()
        {
            if (_currentState == HeroState.Dead) return;

            UpdateCooldowns();
            UpdateMovement();
            UpdateAttack();
            UpdateHealthRegen();
        }

        private void UpdateCooldowns()
        {
            List<string> skills = new List<string>(_skillCooldowns.Keys);
            foreach (var skillName in skills)
            {
                if (_skillCooldowns[skillName] > 0)
                {
                    _skillCooldowns[skillName] -= Time.deltaTime;
                    if (_skillCooldowns[skillName] <= 0)
                    {
                        _skillCooldowns[skillName] = 0;
                        OnSkillReady?.Invoke(skillName);
                    }
                }
            }
        }

        private void UpdateMovement()
        {
            if (!_isMoving) return;

            Vector3 direction = (_targetPosition - transform.position).normalized;
            transform.position += direction * _moveSpeed * Time.deltaTime;

            if (_spriteRenderer != null)
            {
                _spriteRenderer.flipX = direction.x < 0;
            }

            float distance = Vector3.Distance(transform.position, _targetPosition);
            if (distance <= _arrivalThreshold)
            {
                _isMoving = false;
                _currentState = HeroState.Idle;

                if (_animator != null)
                {
                    _animator.SetBool("IsMoving", false);
                }
            }
        }

        private void UpdateAttack()
        {
            if (_currentState != HeroState.Idle) return;

            if (_currentTarget == null || _currentTarget.IsDead)
            {
                FindTarget();
            }

            if (_currentTarget != null && _attackCooldown <= 0)
            {
                Attack();
            }

            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        private void UpdateHealthRegen()
        {
            if (_currentStats.healthRegen > 0 && _currentHealth < _currentStats.maxHealth)
            {
                _currentHealth += _currentStats.healthRegen * Time.deltaTime;
                if (_currentHealth > _currentStats.maxHealth)
                {
                    _currentHealth = _currentStats.maxHealth;
                }
                OnHealthChanged?.Invoke(_currentHealth);
            }
        }

        public void MoveTo(Vector3 position)
        {
            _targetPosition = position;
            _isMoving = true;
            _currentState = HeroState.Moving;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", true);
            }
        }

        public void StopMoving()
        {
            _isMoving = false;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", false);
            }
        }

        private void FindTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            _currentTarget = spawner.GetClosestEnemy(transform.position, _currentStats.attackRange);
        }

        private void Attack()
        {
            if (_currentTarget == null) return;

            _currentState = HeroState.Attacking;
            _attackCooldown = 1f / _currentStats.attackSpeed;

            if (_animator != null)
            {
                _animator.SetTrigger("Attack");
            }

           // 在第211行和第257行添加转换
            _currentTarget.TakeDamage(Mathf.RoundToInt(_currentStats.attackDamage), DamageType.Physical);

            _currentState = HeroState.Idle;
        }

        public bool UseSkill(int skillIndex)
        {
            if (skillIndex < 0 || skillIndex >= _heroData.skills.Length) return false;

            HeroData.HeroSkill skill = _heroData.skills[skillIndex];

            if (_skillCooldowns[skill.skillName] > 0) return false;

            _skillCooldowns[skill.skillName] = skill.cooldown;
            _currentState = HeroState.UsingSkill;

            if (_animator != null)
            {
                _animator.SetTrigger("Skill");
            }

            ExecuteSkill(skill);

            OnSkillUsed?.Invoke(skill.skillName);
            EventBus.Publish(new SkillUsedEvent { SkillName = skill.skillName });

            _currentState = HeroState.Idle;
            return true;
        }

        private void ExecuteSkill(HeroData.HeroSkill skill)
        {
            if (skill.effectPrefab != null)
            {
                Instantiate(skill.effectPrefab, transform.position, Quaternion.identity);
            }

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, skill.effectRadius);

            foreach (var enemy in enemiesInRange)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第211行和第257行添加转换
enemy.TakeDamage(Mathf.RoundToInt(skill.effectValue), DamageType.Magic);
                }
            }
        }

        public void TakeDamage(float damage)
        {
            if (_currentState == HeroState.Dead) return;

            float actualDamage = damage * (1f - _currentStats.armor / 100f);
            _currentHealth -= actualDamage;

            OnHealthChanged?.Invoke(_currentHealth);

            if (_animator != null)
            {
                _animator.SetTrigger("Hit");
            }

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        public void Heal(float amount)
        {
            _currentHealth += amount;
            if (_currentHealth > _currentStats.maxHealth)
            {
                _currentHealth = _currentStats.maxHealth;
            }
            OnHealthChanged?.Invoke(_currentHealth);
        }

        public void AddExp(float exp)
        {
            _currentExp += exp;
            OnExpChanged?.Invoke(_currentExp);

            while (_currentExp >= _expToNextLevel)
            {
                LevelUp();
            }
        }

        private void LevelUp()
        {
            _currentExp -= _expToNextLevel;
            _currentLevel++;
            _expToNextLevel *= 1.5f;

            _currentStats.maxHealth *= 1.1f;
            _currentStats.attackDamage *= 1.1f;
            _currentHealth = _currentStats.maxHealth;

            OnLevelUp?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetTrigger("LevelUp");
            }
        }

        private void Die()
        {
            _currentState = HeroState.Dead;
            OnDeath?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetBool("IsDead", true);
            }
        }

        public void Revive()
        {
            _currentHealth = _currentStats.maxHealth;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsDead", false);
            }
        }

        public float GetSkillCooldown(string skillName)
        {
            return _skillCooldowns.TryGetValue(skillName, out float cd) ? cd : 0f;
        }

        public float GetSkillCooldownPercent(string skillName)
        {
            foreach (var skill in _heroData.skills)
            {
                if (skill.skillName == skillName)
                {
                    return GetSkillCooldown(skillName) / skill.cooldown;
                }
            }
            return 0f;
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Data;

namespace TowerDefense.Hero
{
    public class HeroController : MonoBehaviour
    {
        [Header("Hero")]
        [SerializeField] private Hero _hero;
        [SerializeField] private HeroData _heroData;

        [Header("Movement Settings")]
        [SerializeField] private bool _useClickMovement = true;
        [SerializeField] private LayerMask _groundLayer;

        [Header("Skill Keys")]
        [SerializeField] private KeyCode _skill1Key = KeyCode.Q;
        [SerializeField] private KeyCode _skill2Key = KeyCode.W;
        [SerializeField] private KeyCode _skill3Key = KeyCode.E;

        private Camera _mainCamera;

        private void Awake()
        {
            _mainCamera = Camera.main;

            if (_hero == null)
            {
                _hero = GetComponent<Hero>();
            }
        }

        private void Start()
        {
            if (_hero != null && _heroData != null)
            {
                _hero.Initialize(_heroData);
            }
        }

        private void Update()
        {
            if (_hero == null || _hero.IsDead) return;

            HandleMovement();
            HandleSkills();
        }

        private void HandleMovement()
        {
            if (!_useClickMovement) return;

            if (Input.GetMouseButtonDown(1) && !EventSystem.current.IsPointerOverGameObject())
            {
                Ray ray = _mainCamera.ScreenPointToRay(Input.mousePosition);
                RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction, Mathf.Infinity, _groundLayer);

                if (hit.collider != null)
                {
                    _hero.MoveTo(hit.point);
                }
                else
                {
                    Vector3 worldPosition = _mainCamera.ScreenToWorldPoint(Input.mousePosition);
                    worldPosition.z = 0;
                    _hero.MoveTo(worldPosition);
                }
            }
        }

        private void HandleSkills()
        {
            if (_heroData == null || _heroData.skills == null) return;

            if (Input.GetKeyDown(_skill1Key) && _heroData.skills.Length > 0)
            {
                _hero.UseSkill(0);
            }
            else if (Input.GetKeyDown(_skill2Key) && _heroData.skills.Length > 1)
            {
                _hero.UseSkill(1);
            }
            else if (Input.GetKeyDown(_skill3Key) && _heroData.skills.Length > 2)
            {
                _hero.UseSkill(2);
            }
        }

        public void UseSkillByIndex(int index)
        {
            if (_hero != null)
            {
                _hero.UseSkill(index);
            }
        }

        public void SetHeroData(HeroData data)
        {
            _heroData = data;
            if (_hero != null)
            {
                _hero.Initialize(_heroData);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.Events;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.UI;

namespace TowerDefense.Tower
{
    /// <summary>
    /// 塔槽位组件 - 管理塔的放置、移除、升级和售卖
    /// </summary>
    public class TowerSlot : MonoBehaviour
    {
        [Header("Slot Settings")]
        [Tooltip("是否已被占用")]
        [SerializeField] private bool _isOccupied = false;

        [Tooltip("当前塔实例")]
        [SerializeField] private Tower _currentTower;

        [Tooltip("高亮效果物体")]
        [SerializeField] private GameObject _highlight;

        [Tooltip("建造指示器")]
        [SerializeField] private GameObject _buildIndicator;

        [Header("Slot Type")]
        [Tooltip("槽位类型")]
        [SerializeField] private LevelData.SlotType _slotType = LevelData.SlotType.Normal;

        [Header("Spawn Settings")]
        [Tooltip("塔的Z轴位置")]
        [SerializeField] private float _towerZPosition = -1f;

        [Tooltip("塔的缩放")]
        [SerializeField] private Vector3 _towerScale = Vector3.one;

        [Header("Build Button Settings")]
        [Tooltip("可以建造的塔列表")]
        [SerializeField] private TowerData[] buildableTowers;

        [Header("Events")]
        [Tooltip("塔放置事件")]
        public UnityEvent OnTowerPlaced;

        [Tooltip("塔移除事件")]
        [SerializeField] private UnityEvent OnTowerRemoved;

        [Tooltip("槽位选中事件")]
        public UnityEvent OnSlotSelected;

        /// <summary>
        /// 是否已被占用
        /// </summary>
        public bool IsOccupied => _isOccupied;

        /// <summary>
        /// 当前塔实例
        /// </summary>
        public Tower CurrentTower => _currentTower;

        /// <summary>
        /// 槽位类型
        /// </summary>
        public LevelData.SlotType SlotType => _slotType;

        /// <summary>
        /// 是否处于悬停状态
        /// </summary>
        private bool _isHovered = false;

        /// <summary>
        /// 是否处于选中状态
        /// </summary>
        private bool _isSelected = false;

        /// <summary>
        /// 初始化组件
        /// </summary>
        private void Awake()
        {
           // Debug.Log($"TowerSlot {gameObject.name} initialized");

            // 初始化高亮和建造指示器状态
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(!_isOccupied);
            }
        }

        /// <summary>
        /// 鼠标进入槽位
        /// </summary>
        private void OnMouseEnter()
        {
            if (!_isOccupied)
            {
                _isHovered = true;
                // Debug.Log($"Mouse entered slot: {gameObject.name}");

                // 显示高亮效果
                if (_highlight != null)
                {
                    _highlight.SetActive(true);
                }
            }
        }

        /// <summary>
        /// 鼠标离开槽位
        /// </summary>
        private void OnMouseExit()
        {
            _isHovered = false;
            // 非选中状态下隐藏高亮
            if (_highlight != null && !_isSelected)
            {
                _highlight.SetActive(false);
            }
        }

        /// <summary>
        /// 鼠标点击槽位
        /// </summary>
        private void OnMouseDown()
        {
            Debug.Log($"Slot clicked: {gameObject.name}, IsOccupied: {_isOccupied}");

            // 关闭其他面板
            HideAllPanels();

            if (!_isOccupied)
            {
                SelectSlot();
                ShowTowerSelectPanel();
            }
            else
            {
                SelectSlot();
                ShowTowerInfoPanel();
            }
        }

        /// <summary>
        /// 选中槽位
        /// </summary>
        public void SelectSlot()
        {
            _isSelected = true;
            OnSlotSelected?.Invoke();
                // Debug.Log($"Slot selected: {gameObject.name}");

            // 如果有塔，显示攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.ShowRange();
            }
        }

        /// <summary>
        /// 取消选中槽位
        /// </summary>
        public void DeselectSlot()
        {
            _isSelected = false;
            // 隐藏高亮效果
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 如果有塔，隐藏攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.HideRange();
            }
                // Debug.Log($"Slot deselected: {gameObject.name}");
        }

        /// <summary>
        /// 显示塔选择面板
        /// </summary>
        private void ShowTowerSelectPanel()
        {
            Debug.Log("🔍 尝试查找 TowerSelectPanel...");

            TowerSelectPanel panel = FindObjectOfType<TowerSelectPanel>();
            Debug.Log($"   FindObjectOfType 结果: {panel != null}");

            if (panel == null)
            {
                GameObject panelObj = GameObject.Find("TowerSelectPanel");
                Debug.Log($"   GameObject.Find 结果: {panelObj != null}");

                if (panelObj != null)
                {
                    panel = panelObj.GetComponent<TowerSelectPanel>();
                    Debug.Log($"   GetComponent 结果: {panel != null}");

                    if (panel == null)
                    {
                        panel = panelObj.AddComponent<TowerSelectPanel>();
                        Debug.Log("✅ 动态添加了 TowerSelectPanel 组件");
                    }
                }
                else
                {
                    // 自动创建一个简单的 TowerSelectPanel
                    Debug.Log("📦 自动创建 TowerSelectPanel...");
                    panelObj = new GameObject("TowerSelectPanel");
                    Canvas canvas = FindObjectOfType<Canvas>();
                    if (canvas != null)
                    {
                        panelObj.transform.SetParent(canvas.transform, false);
                    }

                    panel = panelObj.AddComponent<TowerSelectPanel>();
                    Debug.Log("✅ 自动创建了 TowerSelectPanel (基础版本)");
                }
            }

            if (panel != null)
            {
                Debug.Log("✅ 找到 TowerSelectPanel，显示面板");
                panel.Show(this);
            }
            else
            {
                Debug.Log("⚠️ 找不到 TowerSelectPanel，降级使用旧按钮");
                // 降级使用旧的建造按钮
                if (BuildButtonManager.Instance != null)
                {
                    BuildButtonManager.Instance.ShowBuildButton(this);
                }
            }
        }

        /// <summary>
        /// 显示塔信息面板
        /// </summary>
        private void ShowTowerInfoPanel()
        {
            TowerInfoPanel panel = FindObjectOfType<TowerInfoPanel>();
            if (panel != null && _currentTower != null)
            {
                panel.Show(_currentTower);
            }
        }

        /// <summary>
        /// 隐藏所有UI面板
        /// </summary>
        private void HideAllPanels()
        {
            TowerSelectPanel selectPanel = FindObjectOfType<TowerSelectPanel>();
            if (selectPanel != null)
            {
                selectPanel.Hide();
            }

            TowerInfoPanel infoPanel = FindObjectOfType<TowerInfoPanel>();
            if (infoPanel != null)
            {
                infoPanel.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

        /// <summary>
        /// 被管理器调用的建造按钮点击
        /// </summary>
        public void OnBuildButtonClickedByManager()
        {
                // Debug.Log("OnBuildButtonClickedByManager called!");

            // 尝试放置塔
            TowerData towerToBuild = GetTowerDataToBuild();

            if (towerToBuild != null)
            {
                bool success = PlaceTower(towerToBuild);

                if (success)
                {
                    // Debug.Log("✅ Tower built successfully!");
                }
                else
                {
                    // Debug.Log("❌ Failed to build tower!");
                }
            }
            else
            {
                // Debug.LogError("❌ No tower data to build!");
            }
        }

        /// <summary>
        /// 获取要建造的塔数据
        /// </summary>
        private TowerData GetTowerDataToBuild()
        {
            // 优先使用配置的塔列表
            if (buildableTowers != null && buildableTowers.Length > 0)
            {
                    // Debug.Log($"Using configured tower: {buildableTowers[0].towerName}");
                return buildableTowers[0];
            }

            // 尝试从Resources/Data/Towers/加载
            Debug.Log("Trying to load from Resources/Data/Towers/");
            TowerData[] towerDatas1 = Resources.LoadAll<TowerData>("Data/Towers");
            if (towerDatas1.Length > 0)
            {
                     Debug.Log($"Found {towerDatas1.Length} tower data assets in Data/Towers/");
                return towerDatas1[0];
            }

            // 尝试从Resources/Data/加载
            Debug.Log("Trying to load from Resources/Data/");
            TowerData[] towerDatas2 = Resources.LoadAll<TowerData>("Data");
            if (towerDatas2.Length > 0)
            {
                Debug.Log($"Found {towerDatas2.Length} tower data assets in Data/");
                return towerDatas2[0];
            }

                Debug.LogError("❌ No tower data found!");
            return null;
        }

        /// <summary>
        /// 在槽位放置塔
        /// </summary>
        /// <param name="towerData">塔数据</param>
        /// <returns>是否放置成功</returns>
        public bool PlaceTower(TowerData towerData)
        {
            // 检查是否已被占用
            if (_isOccupied) return false;

            // 检查金币是否足够
            if (!GameManager.Instance.SpendGold(towerData.levels[0].cost))
            {
                Debug.Log("❌ Not enough gold!");
                return false;
            }

            // 设置生成位置（调整Z轴和缩放）
            Vector3 spawnPos = transform.position;
            spawnPos.z = _towerZPosition;

            // 实例化塔
            GameObject towerObj = Instantiate(towerData.towerPrefab, spawnPos, Quaternion.identity);

            // 应用缩放
            if (_towerScale != Vector3.one)
            {
                towerObj.transform.localScale = _towerScale;
            }

            _currentTower = towerObj.GetComponent<Tower>();

            // 初始化塔
            if (_currentTower != null)
            {
                _currentTower.Initialize(towerData, this);
            }

            // 更新状态
            _isOccupied = true;

            // 更新UI显示
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(false);
            }
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 触发事件
            OnTowerPlaced?.Invoke();
            EventBus.Publish(new TowerPlacedEvent { Tower = towerObj, Cost = towerData.levels[0].cost });

            return true;
        }

        /// <summary>
        /// 移除塔（不返还金币）
        /// </summary>
        public void RemoveTower()
        {
            _currentTower = null;
            _isOccupied = false;

            // 显示建造指示器
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(true);
            }

            OnTowerRemoved?.Invoke();
        }

        /// <summary>
        /// 售卖塔（返还部分金币）
        /// </summary>
        public void SellTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Sell();
        }

        /// <summary>
        /// 升级塔
        /// </summary>
        public void UpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Upgrade();
        }

        /// <summary>
        /// 获取塔的售卖价值
        /// </summary>
        /// <returns>售卖金币数</returns>
        public int GetTowerSellValue()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetSellValue();
        }

        /// <summary>
        /// 获取塔的升级费用
        /// </summary>
        /// <returns>升级金币数</returns>
        public int GetTowerUpgradeCost()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetUpgradeCost();
        }

        /// <summary>
        /// 检查塔是否可以升级
        /// </summary>
        /// <returns>是否可升级</returns>
        public bool CanUpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return false;
            return !_currentTower.IsMaxLevel;
        }

        /// <summary>
        /// 绘制Gizmos（编辑器模式下）
        /// </summary>
        private void OnDrawGizmos()
        {
            // 绿色表示可建造，红色表示已占用
            Gizmos.color = _isOccupied ? Color.red : Color.green;
            Gizmos.DrawWireSphere(transform.position, 0.3f);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using UnityEngine;
using TowerDefense.Tower;

public class BuildButtonManager : MonoBehaviour
{
    public static BuildButtonManager Instance { get; private set; }

    [Tooltip("建造按钮预制体")]
    public GameObject buildButtonPrefab;

    [Tooltip("Canvas引用")]
    public Canvas uiCanvas;

    [Tooltip("按钮偏移")]
    public Vector2 buttonOffset = new Vector2(0, 50);

    private GameObject _currentButton;
    private TowerSlot _currentSlot;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        if (uiCanvas == null)
        {
            uiCanvas = FindObjectOfType<Canvas>();
        }
    }

    /// <summary>
    /// 显示建造按钮
    /// </summary>
    public void ShowBuildButton(TowerSlot slot)
    {
        // 如果有其他按钮，先隐藏
        HideBuildButton();

        if (buildButtonPrefab == null || uiCanvas == null)
        {
            Debug.LogError("BuildButtonManager: Missing prefab or Canvas!");
            return;
        }

        // 计算按钮位置
        Vector3 worldPos = Camera.main.WorldToScreenPoint(slot.transform.position);
        worldPos += new Vector3(buttonOffset.x, buttonOffset.y, 0);

        // 实例化按钮
        _currentButton = Instantiate(buildButtonPrefab);
        _currentButton.transform.SetParent(uiCanvas.transform, false);
        _currentButton.transform.position = worldPos;

        // 绑定事件
        UnityEngine.UI.Button button = _currentButton.GetComponent<UnityEngine.UI.Button>();
        if (button != null)
        {
            button.onClick.AddListener(() => OnBuildButtonClicked(slot));
        }

        _currentSlot = slot;
        Debug.Log($"Build button shown for slot: {slot.name}");
    }

    /// <summary>
    /// 隐藏建造按钮
    /// </summary>
    public void HideBuildButton()
    {
        if (_currentButton != null)
        {
            Destroy(_currentButton);
            _currentButton = null;
        }
        _currentSlot = null;
    }

    /// <summary>
    /// 建造按钮点击
    /// </summary>
    private void OnBuildButtonClicked(TowerSlot slot)
    {
        Debug.Log("Build button clicked!");

        // 先隐藏按钮
        HideBuildButton();

        // 让槽位自己处理建造逻辑
        // 这里我们直接调用一个方法
        slot.OnBuildButtonClickedByManager();
    }

    /// <summary>
    /// 检查当前是否显示了按钮
    /// </summary>
    public bool IsButtonShowing()
    {
        return _currentButton != null;
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class MainMenuUI : MonoBehaviour
    {
        [Header("Panels")]
        [SerializeField] private GameObject _mainPanel;
        [SerializeField] private GameObject _levelSelectPanel;
        [SerializeField] private GameObject _settingsPanel;

        [Header("Level Selection")]
        [SerializeField] private Transform _levelButtonContainer;
        [SerializeField] private GameObject _levelButtonPrefab;

        [Header("Settings")]
        [SerializeField] private Slider _musicSlider;
        [SerializeField] private Slider _sfxSlider;
        [SerializeField] private Toggle _fullscreenToggle;

        [Header("Level Data")]
        [SerializeField] private LevelData[] _levels;

        private void Start()
        {
            ShowMainPanel();
            LoadSettings();
        }

        public void ShowMainPanel()
        {
            if (_mainPanel != null) _mainPanel.SetActive(true);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);
        }

        public void ShowLevelSelect()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(true);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);

            GenerateLevelButtons();
        }

        public void ShowSettings()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(true);
        }

        public void StartLevel(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _levels.Length)
            {
                SceneManager.LoadScene(_levels[levelIndex].sceneName);
            }
        }

        public void QuitGame()
        {
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void GenerateLevelButtons()
        {
            if (_levelButtonContainer == null || _levelButtonPrefab == null) return;

            foreach (Transform child in _levelButtonContainer)
            {
                Destroy(child.gameObject);
            }

            for (int i = 0; i < _levels.Length; i++)
            {
                GameObject buttonObj = Instantiate(_levelButtonPrefab, _levelButtonContainer);
                LevelButton levelButton = buttonObj.GetComponent<LevelButton>();

                if (levelButton != null)
                {
                    levelButton.Setup(_levels[i], i, this);
                }
            }
        }

        #region Settings

        public void OnMusicVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("MusicVolume", value);
            PlayerPrefs.Save();
        }

        public void OnSFXVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("SFXVolume", value);
            PlayerPrefs.Save();
        }

        public void OnFullscreenToggled(bool isFullscreen)
        {
            Screen.fullScreen = isFullscreen;
            PlayerPrefs.SetInt("Fullscreen", isFullscreen ? 1 : 0);
            PlayerPrefs.Save();
        }

        private void LoadSettings()
        {
            if (_musicSlider != null)
            {
                _musicSlider.value = PlayerPrefs.GetFloat("MusicVolume", 1f);
            }
            if (_sfxSlider != null)
            {
                _sfxSlider.value = PlayerPrefs.GetFloat("SFXVolume", 1f);
            }
            if (_fullscreenToggle != null)
            {
                _fullscreenToggle.isOn = PlayerPrefs.GetInt("Fullscreen", 1) == 1;
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Tower;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerSelectPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;
        [SerializeField] private Text _slotInfoText;

        [Header("Text Settings")]
        [SerializeField] private Font _buttonFont;


        [Header("Tower Data")]
        [SerializeField] private TowerData[] _availableTowers;

        private TowerSlot _currentSlot;
        private TowerData[] _towerDatas;

        private void Awake()
        {
            Debug.Log($"TowerSelectPanel Awake - _panel: {_panel != null}, _container: {_towerButtonContainer != null}, _prefab: {_towerButtonPrefab != null}, _text: {_slotInfoText != null}");

            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            LoadTowerData();
        }

        private void LoadTowerData()
        {
            if (_availableTowers != null && _availableTowers.Length > 0)
            {
                _towerDatas = _availableTowers;
            }
            else
            {
                _towerDatas = Resources.LoadAll<TowerData>("Data");
            }
        }

        public void Show(TowerSlot slot)
        {
            Debug.Log($"TowerSelectPanel.Show() called - _panel: {_panel != null}, _towerDatas length: {_towerDatas?.Length ?? 0}");

            _currentSlot = slot;

            if (_panel == null)
            {
                CreateSimplePanel();
            }

            if (_slotInfoText != null)
            {
                _slotInfoText.text = "选择要建造的塔";
            }

            RefreshTowerButtons();

            if (_panel != null)
            {
                _panel.SetActive(true);
                Debug.Log("✅ TowerSelectPanel 已显示");
            }
            else
            {
                Debug.LogWarning("⚠️ TowerSelectPanel 的 _panel 字段未设置！请在 Inspector 中设置。");
            }
        }

        private void CreateSimplePanel()
        {
            Debug.Log("📦 自动创建简单的塔选择面板...");

            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null)
            {
                Debug.LogError("❌ 找不到 Canvas！");
                return;
            }

            GameObject panelObj = new GameObject("TowerSelectPanel_Content");
            panelObj.transform.SetParent(canvas.transform, false);

            Image panelImage = panelObj.AddComponent<Image>();
            panelImage.color = new Color(0.2f, 0.2f, 0.2f, 0.95f);

            RectTransform rect = panelObj.GetComponent<RectTransform>();
            rect.sizeDelta = new Vector2(300, 400);
            rect.anchorMin = new Vector2(0.5f, 0.5f);
            rect.anchorMax = new Vector2(0.5f, 0.5f);
            rect.pivot = new Vector2(0.5f, 0.5f);
            rect.anchoredPosition = Vector2.zero;

            GameObject titleObj = new GameObject("Title");
            titleObj.transform.SetParent(panelObj.transform, false);
            Text titleText = titleObj.AddComponent<Text>();
            titleText.text = "选择要建造的塔";
            titleText.fontSize = 24;
            titleText.alignment = TextAnchor.MiddleCenter;
            _slotInfoText = titleText;

            RectTransform titleRect = titleObj.GetComponent<RectTransform>();
            titleRect.sizeDelta = new Vector2(280, 40);
            titleRect.anchorMin = new Vector2(0.5f, 1);
            titleRect.anchorMax = new Vector2(0.5f, 1);
            titleRect.pivot = new Vector2(0.5f, 1);
            titleRect.anchoredPosition = new Vector2(0, -20);

            GameObject containerObj = new GameObject("TowerButtonContainer");
            containerObj.transform.SetParent(panelObj.transform, false);

            RectTransform containerRect = containerObj.GetComponent<RectTransform>();
            containerRect.sizeDelta = new Vector2(260, 300);
            containerRect.anchorMin = new Vector2(0.5f, 0);
            containerRect.anchorMax = new Vector2(0.5f, 1);
            containerRect.pivot = new Vector2(0.5f, 0.5f);
            containerRect.anchoredPosition = new Vector2(0, -20);

            VerticalLayoutGroup layout = containerObj.AddComponent<VerticalLayoutGroup>();
            layout.padding = new RectOffset(10, 10, 10, 10);
            layout.spacing = 10;
            layout.childAlignment = TextAnchor.UpperCenter;

            _towerButtonContainer = containerRect;

            GameObject closeBtnObj = new GameObject("CloseButton");
            closeBtnObj.transform.SetParent(panelObj.transform, false);

            Button closeBtn = closeBtnObj.AddComponent<Button>();
            closeBtn.onClick.AddListener(Hide);

            Image closeImage = closeBtnObj.AddComponent<Image>();
            closeImage.color = new Color(0.6f, 0.2f, 0.2f);

            Text closeText = closeBtnObj.AddComponent<Text>();
            closeText.text = "关闭";
            closeText.alignment = TextAnchor.MiddleCenter;

            RectTransform closeRect = closeBtnObj.GetComponent<RectTransform>();
            closeRect.sizeDelta = new Vector2(200, 40);
            closeRect.anchorMin = new Vector2(0.5f, 0);
            closeRect.anchorMax = new Vector2(0.5f, 0);
            closeRect.pivot = new Vector2(0.5f, 0);
            closeRect.anchoredPosition = new Vector2(0, 20);

            _panel = panelObj;
            _panel.SetActive(false);

            Debug.Log("✅ 简单塔选择面板创建完成");
        }

        public void Hide()
        {
            _currentSlot = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void RefreshTowerButtons()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                Destroy(child.gameObject);
            }

            foreach (var towerData in _towerDatas)
            {
                CreateTowerButton(towerData);
            }
        }

        private void CreateTowerButton(TowerData towerData)
        {
            Debug.Log($"🆕 创建塔按钮: {towerData.towerName}, icon? {(towerData.icon != null ? "✅ 设置了" + towerData.icon.name : "❌ 空")}");

            GameObject buttonObj;

            if (_towerButtonPrefab == null)
            {
                buttonObj = new GameObject($"TowerButton_{towerData.towerName}");
                buttonObj.transform.SetParent(_towerButtonContainer, false);

                Button button = buttonObj.AddComponent<Button>();
                Image bgImage = buttonObj.AddComponent<Image>();
                bgImage.color = new Color(0.4f, 0.4f, 0.6f);

                RectTransform buttonRect = buttonObj.GetComponent<RectTransform>();
                buttonRect.sizeDelta = new Vector2(70, 85);

                if (towerData.icon != null)
                {
                    Debug.Log($"✅ 找到塔图标: {towerData.towerName} -> {towerData.icon.name}");

                    GameObject iconObj = new GameObject("Icon");
                    iconObj.transform.SetParent(buttonObj.transform, false);

                    Image iconImage = iconObj.AddComponent<Image>();
                    iconImage.sprite = towerData.icon;
                    iconImage.preserveAspect = true;

                    RectTransform iconRect = iconObj.GetComponent<RectTransform>();
                    iconRect.anchorMin = new Vector2(0.5f, 0.4f);
                    iconRect.anchorMax = new Vector2(0.5f, 1f);
                    iconRect.offsetMin = new Vector2(-30, 0);
                    iconRect.offsetMax = new Vector2(30, 0);
                }
                else
                {
                    Debug.LogWarning($"❌ 没有找到塔图标: {towerData.towerName}");
                }

                GameObject textObj = new GameObject("Text");
                textObj.transform.SetParent(buttonObj.transform, false);

                Outline outline = textObj.AddComponent<Outline>();
                outline.effectColor = Color.black;
                outline.effectDistance = new Vector2(2, -2);

                Text text = textObj.AddComponent<Text>();
                text.text = $"{GetTowerPrice(towerData)}";

                if (_buttonFont != null)
                {
                    text.font = _buttonFont;
                }

                text.fontSize = 26;
                text.fontStyle = FontStyle.Bold;
                text.alignment = TextAnchor.LowerCenter;
                text.color = new Color(1f, 0.9f, 0f);
                text.horizontalOverflow = HorizontalWrapMode.Overflow;
                text.verticalOverflow = VerticalWrapMode.Overflow;

                RectTransform textRect = textObj.GetComponent<RectTransform>();
                textRect.anchorMin = Vector2.zero;
                textRect.anchorMax = new Vector2(1f, 0.35f);
                textRect.offsetMin = Vector2.zero;
                textRect.offsetMax = Vector2.zero;

                bool canAfford = GameManager.Instance.HasEnoughGold(GetTowerPrice(towerData));
                button.interactable = canAfford;
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                if (!canAfford)
                {
                    bgImage.color = new Color(0.3f, 0.3f, 0.3f);
                }
            }
            else
            {
                buttonObj = Instantiate(_towerButtonPrefab, _towerButtonContainer);
                buttonObj.name = $"TowerButton_{towerData.towerName}";

                TowerButton button = buttonObj.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.Initialize(towerData, this);
                }
                else
                {
                    SetupButtonManually(buttonObj, towerData);
                }
            }
        }

        private int GetTowerPrice(TowerData towerData)
        {
            if (towerData.levels != null && towerData.levels.Length > 0)
            {
                return towerData.levels[0].cost;
            }
            return 0;
        }

        private void SetupButtonManually(GameObject buttonObj, TowerData towerData)
        {
            Text nameText = buttonObj.GetComponentInChildren<Text>();
            if (nameText != null)
            {
                nameText.text = towerData.towerName;
            }

            Image[] images = buttonObj.GetComponentsInChildren<Image>();
            foreach (var img in images)
            {
                if (img.gameObject != buttonObj && towerData.icon != null && img.sprite == null)
                {
                    img.sprite = towerData.icon;
                    img.preserveAspect = true;
                    break;
                }
            }

            Button button = buttonObj.GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                bool canAfford = GameManager.Instance.HasEnoughGold(towerData.levels[0].cost);
                button.interactable = canAfford;
            }
        }

        public void OnTowerSelected(TowerData towerData)
        {
            if (_currentSlot != null)
            {
                bool success = _currentSlot.PlaceTower(towerData);
                if (success)
                {
                    Hide();
                }
            }
        }

        public void UpdateButtonStates()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                TowerButton button = child.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.UpdateState();
                }
            }
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateButtonStates();
        }
    }

    public class TowerButton : MonoBehaviour
    {
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _costText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Image _icon;

        private TowerData _towerData;
        private TowerSelectPanel _panel;

        public void Initialize(TowerData towerData, TowerSelectPanel panel)
        {
            _towerData = towerData;
            _panel = panel;

            if (_nameText != null)
            {
                _nameText.text = towerData.towerName;
            }

            TowerData.TowerStats stats = towerData.levels[0];
            if (_costText != null)
            {
                _costText.text = $"{stats.cost} G";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"范围: {stats.attackRange}";
            }

            if (towerData.icon != null)
            {
                Debug.Log($"✅ TowerButton 找到塔图标: {towerData.towerName} -> {towerData.icon.name}");

                if (_icon != null)
                {
                    _icon.sprite = towerData.icon;
                    _icon.gameObject.SetActive(true);
                }

                Image[] allImages = GetComponentsInChildren<Image>();
                foreach (var img in allImages)
                {
                    if (img.gameObject != gameObject && img.sprite == null)
                    {
                        img.sprite = towerData.icon;
                        img.preserveAspect = true;
                        Debug.Log($"✅ 自动填充图标到 Image: {img.gameObject.name}");
                        break;
                    }
                }
            }
            else
            {
                Debug.LogWarning($"❌ TowerButton 没有塔图标: {towerData.towerName}");

                if (_icon != null)
                {
                    _icon.gameObject.SetActive(false);
                }
            }

            UpdateState();

            Button button = GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(OnClicked);
            }
        }

        public void UpdateState()
        {
            Button button = GetComponent<Button>();
            if (button != null)
            {
                bool canAfford = GameManager.Instance.HasEnoughGold(_towerData.levels[0].cost);
                button.interactable = canAfford;

                Image image = GetComponent<Image>();
                if (image != null)
                {
                    image.color = canAfford ? Color.white : Color.grey;
                }
            }
        }

        private void OnClicked()
        {
            if (_panel != null)
            {
                _panel.OnTowerSelected(_towerData);
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Utils
{
    public class PathCreator : MonoBehaviour
    {
        [Header("Path Settings")]
        [SerializeField] private List<Vector3> _waypoints = new List<Vector3>();
        [SerializeField] private Color _pathColor = Color.red;
        [SerializeField] private float _waypointRadius = 0.3f;
        [SerializeField] private bool _showPath = true;

        [Header("Editing")]
        [SerializeField] private bool _editingMode = false;
        [SerializeField] private int _selectedWaypoint = -1;

        public List<Vector3> Waypoints => _waypoints;
        public int WaypointCount => _waypoints.Count;

        public void AddWaypoint(Vector3 position)
        {
            _waypoints.Add(position);
        }

        public void AddWaypointAtMouse()
        {
            Vector3 mousePos = Camera.main.ScreenToWorldPoint(Input.mousePosition);
            mousePos.z = 0;
            AddWaypoint(mousePos);
        }

        public void RemoveWaypoint(int index)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                _waypoints.RemoveAt(index);
            }
        }

        public void ClearPath()
        {
            _waypoints.Clear();
        }

        public void MoveWaypoint(int index, Vector3 newPosition)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                _waypoints[index] = newPosition;
            }
        }

        public void InsertWaypoint(int index, Vector3 position)
        {
            if (index >= 0 && index <= _waypoints.Count)
            {
                _waypoints.Insert(index, position);
            }
        }

        public Vector3 GetWaypoint(int index)
        {
            if (index >= 0 && index < _waypoints.Count)
            {
                return _waypoints[index];
            }
            return Vector3.zero;
        }

        public float GetTotalDistance()
        {
            float distance = 0f;
            for (int i = 1; i < _waypoints.Count; i++)
            {
                distance += Vector3.Distance(_waypoints[i - 1], _waypoints[i]);
            }
            return distance;
        }

        public List<Vector3> GetSmoothPath(int subdivisions = 10)
        {
            if (_waypoints.Count < 2) return new List<Vector3>(_waypoints);

            List<Vector3> smoothPath = new List<Vector3>();

            for (int i = 0; i < _waypoints.Count - 1; i++)
            {
                Vector3 start = _waypoints[i];
                Vector3 end = _waypoints[i + 1];

                for (int j = 0; j < subdivisions; j++)
                {
                    float t = j / (float)subdivisions;
                    smoothPath.Add(Vector3.Lerp(start, end, t));
                }
            }

            smoothPath.Add(_waypoints[_waypoints.Count - 1]);

            return smoothPath;
        }

        private void OnDrawGizmos()
        {
            if (!_showPath || _waypoints.Count == 0) return;

            Gizmos.color = _pathColor;

            for (int i = 0; i < _waypoints.Count - 1; i++)
            {
                Gizmos.DrawLine(_waypoints[i], _waypoints[i + 1]);
            }

            for (int i = 0; i < _waypoints.Count; i++)
            {
                Gizmos.color = i == _selectedWaypoint ? Color.yellow : _pathColor;
                Gizmos.DrawWireSphere(_waypoints[i], _waypointRadius);

#if UNITY_EDITOR
                UnityEditor.Handles.Label(_waypoints[i] + Vector3.up * 0.5f, i.ToString());
#endif
            }

            if (_waypoints.Count > 0)
            {
                Gizmos.color = Color.green;
                Gizmos.DrawSphere(_waypoints[0], _waypointRadius * 1.2f);

                Gizmos.color = Color.red;
                Gizmos.DrawSphere(_waypoints[_waypoints.Count - 1], _waypointRadius * 1.2f);
            }
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

public class PathSystem : MonoBehaviour
{
    [Header("Path Settings")]
    [SerializeField] private Transform[] _waypoints;
    [SerializeField] private bool _isClosedLoop = false;
    [SerializeField] private Color _pathColor = Color.cyan;
    
    public int WaypointCount => _waypoints.Length;
    
    private void Awake()
    {
        if (_waypoints == null || _waypoints.Length == 0)
        {
            Debug.LogWarning("No waypoints assigned to PathSystem!");
        }
    }
    
    public Vector3 GetWaypoint(int index)
    {
        if (_waypoints == null || index < 0 || index >= _waypoints.Length)
        {
            return Vector3.zero;
        }
        return _waypoints[index].position;
    }
    
    public Vector3[] GetAllWaypoints()
    {
        if (_waypoints == null) return new Vector3[0];
        
        Vector3[] points = new Vector3[_waypoints.Length];
        for (int i = 0; i < _waypoints.Length; i++)
        {
            points[i] = _waypoints[i].position;
        }
        return points;
    }
    
    public Vector3 GetStartPoint()
    {
        return GetWaypoint(0);
    }
    
    public Vector3 GetEndPoint()
    {
        return GetWaypoint(_waypoints.Length - 1);
    }
    
    private void OnDrawGizmos()
    {
        if (_waypoints == null || _waypoints.Length < 2) return;
        
        Gizmos.color = _pathColor;
        
        for (int i = 0; i < _waypoints.Length - 1; i++)
        {
            Gizmos.DrawLine(_waypoints[i].position, _waypoints[i + 1].position);
        }
        
        if (_isClosedLoop && _waypoints.Length > 1)
        {
            Gizmos.DrawLine(_waypoints[_waypoints.Length - 1].position, _waypoints[0].position);
        }
        
        Gizmos.color = Color.red;
        foreach (var waypoint in _waypoints)
        {
            Gizmos.DrawSphere(waypoint.position, 0.2f);
        }
    }
}

using UnityEngine;
using UnityEngine.Tilemaps;
using System.Collections.Generic;

namespace TowerDefense.Map
{
    public class MapGenerator : MonoBehaviour
    {
        [Header("Tilemaps")]
        [SerializeField] private Tilemap groundMap;
        [SerializeField] private Tilemap pathMap;
        [SerializeField] private Tilemap buildSlotMap;
        [SerializeField] private Tilemap decorationMap;

        [Header("Prefabs")]
        [SerializeField] private GameObject towerSlotPrefab;

        [Header("Map Settings")]
        [SerializeField] private Vector3 mapSize = new Vector3(20, 15, 0);

        private List<Tower.TowerSlot> towerSlots = new List<Tower.TowerSlot>();

        public void InitializeMap()
        {
            GenerateTowerSlots();
            InitializePaths();
        }

        private void GenerateTowerSlots()
        {
            if (buildSlotMap == null || towerSlotPrefab == null) return;

            towerSlots.Clear();

            BoundsInt bounds = buildSlotMap.cellBounds;
            TileBase[] allTiles = buildSlotMap.GetTilesBlock(bounds);

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    TileBase tile = buildSlotMap.GetTile(cellPosition);

                    if (tile != null)
                    {
                        Vector3 worldPosition = buildSlotMap.CellToWorld(cellPosition);
                        worldPosition += new Vector3(0.5f, 0.5f, 0);

                        GameObject slotObj = Instantiate(towerSlotPrefab, worldPosition, Quaternion.identity);
                        slotObj.name = $"TowerSlot_{x}_{y}";

                        Tower.TowerSlot slot = slotObj.GetComponent<Tower.TowerSlot>();
                        if (slot != null)
                        {
                            towerSlots.Add(slot);
                        }
                    }
                }
            }

            Debug.Log($"Generated {towerSlots.Count} tower slots");
        }

        private void InitializePaths()
        {
            if (pathMap == null) return;

            List<Vector3> waypoints = new List<Vector3>();

            BoundsInt bounds = pathMap.cellBounds;
            TileBase[] allTiles = pathMap.GetTilesBlock(bounds);

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    TileBase tile = pathMap.GetTile(cellPosition);

                    if (tile != null)
                    {
                        Vector3 worldPosition = pathMap.CellToWorld(cellPosition);
                        worldPosition += new Vector3(0.5f, 0.5f, 0);
                        waypoints.Add(worldPosition);
                    }
                }
            }

            Debug.Log($"Found {waypoints.Count} path points");
        }

        public List<Tower.TowerSlot> GetTowerSlots()
        {
            return towerSlots;
        }

        public void ClearMap()
        {
            foreach (var slot in towerSlots)
            {
                if (slot != null && slot.CurrentTower != null)
                {
                    slot.SellTower();
                }
            }

            towerSlots.Clear();
        }

        private void OnDrawGizmos()
        {
            if (buildSlotMap != null)
            {
                Gizmos.color = Color.green;
                BoundsInt bounds = buildSlotMap.cellBounds;
                Gizmos.DrawWireCube(bounds.center, bounds.size);
            }

            if (pathMap != null)
            {
                Gizmos.color = Color.red;
                BoundsInt bounds = pathMap.cellBounds;
                Gizmos.DrawWireCube(bounds.center, bounds.size);
            }
        }
    }
}

using System.IO;
using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Save
{
    public class SaveSystem : Singleton<SaveSystem>
    {
        private const string SAVE_FILE = "savedata.json";
        private const string SAVE_FOLDER = "Save";

        private GameSaveData _currentSave;
        private string SavePath => Path.Combine(Application.persistentDataPath, SAVE_FOLDER, SAVE_FILE);

        public GameSaveData CurrentSave => _currentSave;

        protected override void Awake()
        {
            base.Awake();
            LoadGame();
        }

        public void SaveGame()
        {
            string directory = Path.GetDirectoryName(SavePath);
            if (!Directory.Exists(directory))
            {
                Directory.CreateDirectory(directory);
            }

            string json = JsonUtility.ToJson(_currentSave, true);
            File.WriteAllText(SavePath, json);

            Debug.Log($"[SaveSystem] Game saved to {SavePath}");
        }

        public void LoadGame()
        {
            if (File.Exists(SavePath))
            {
                string json = File.ReadAllText(SavePath);
                _currentSave = JsonUtility.FromJson<GameSaveData>(json);
                Debug.Log("[SaveSystem] Game loaded successfully");
            }
            else
            {
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] No save file found, creating new save data");
            }
        }

        public void DeleteSave()
        {
            if (File.Exists(SavePath))
            {
                File.Delete(SavePath);
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] Save file deleted");
            }
        }

        public void SaveLevelProgress(int levelIndex, int stars, int score, float time)
        {
            if (levelIndex < 0) return;

            while (_currentSave.levels.Count <= levelIndex)
            {
                _currentSave.levels.Add(new GameSaveData.LevelSaveData
                {
                    levelIndex = _currentSave.levels.Count,
                    isUnlocked = false,
                    starsEarned = 0,
                    highScore = 0,
                    bestTime = float.MaxValue
                });
            }

            var levelData = _currentSave.levels[levelIndex];
            levelData.isUnlocked = true;
            levelData.starsEarned = Mathf.Max(levelData.starsEarned, stars);
            levelData.highScore = Mathf.Max(levelData.highScore, score);
            levelData.bestTime = Mathf.Min(levelData.bestTime, time);

            _currentSave.levels[levelIndex] = levelData;

            if (levelIndex + 1 < _currentSave.levels.Count)
            {
                var nextLevel = _currentSave.levels[levelIndex + 1];
                nextLevel.isUnlocked = true;
                _currentSave.levels[levelIndex + 1] = nextLevel;
            }

            SaveGame();
        }

        public GameSaveData.LevelSaveData GetLevelData(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _currentSave.levels.Count)
            {
                return _currentSave.levels[levelIndex];
            }
            return new GameSaveData.LevelSaveData { levelIndex = levelIndex, isUnlocked = levelIndex == 0 };
        }

        public void SaveHeroProgress(string heroName, int level, float experience)
        {
            var heroData = _currentSave.heroes.Find(h => h.heroName == heroName);
            if (heroData == null)
            {
                heroData = new GameSaveData.HeroSaveData { heroName = heroName, isUnlocked = true };
                _currentSave.heroes.Add(heroData);
            }

            heroData.level = level;
            heroData.experience = experience;

            SaveGame();
        }

        public GameSaveData.HeroSaveData GetHeroData(string heroName)
        {
            return _currentSave.heroes.Find(h => h.heroName == heroName);
        }

        public void UpdatePlayerStats(int gold, int kills, int waves, float playTime)
        {
            _currentSave.player.totalGold += gold;
            _currentSave.player.totalKills += kills;
            _currentSave.player.totalWavesCompleted += waves;
            _currentSave.player.totalPlayTime += playTime;
            _currentSave.player.totalGamesPlayed++;

            SaveGame();
        }

        public void SaveSettings(float musicVolume, float sfxVolume, bool fullscreen, int quality)
        {
            _currentSave.settings.musicVolume = musicVolume;
            _currentSave.settings.sfxVolume = sfxVolume;
            _currentSave.settings.isFullscreen = fullscreen;
            _currentSave.settings.qualityLevel = quality;

            SaveGame();
        }

        public void LoadSettings()
        {
            AudioListener.volume = _currentSave.settings.sfxVolume;
            Screen.fullScreen = _currentSave.settings.isFullscreen;
            QualitySettings.SetQualityLevel(_currentSave.settings.qualityLevel);
        }

        public int CalculateTotalStars()
        {
            int total = 0;
            foreach (var level in _currentSave.levels)
            {
                total += level.starsEarned;
            }
            _currentSave.totalStars = total;
            return total;
        }
    }
}

