                // 点击到空白处，隐藏按钮
                HideButton();
            }
        }
    }

    private void ShowButton(Vector3 worldPos)
    {
        if (buildButton != null)
        {
            // 计算按钮位置
            Vector3 screenPos = Camera.main.WorldToScreenPoint(worldPos);
            screenPos += new Vector3(0, 60, 0); // 在槽位上方显示

            buildButton.transform.position = screenPos;
            buildButton.gameObject.SetActive(true);
        }
    }

    private void HideButton()
    {
        if (buildButton != null)
        {
            buildButton.gameObject.SetActive(false);
        }
        currentSlot = null;
    }

    private void OnBuildClicked()
    {
        Debug.Log("按钮被点击了！");

        if (currentSlot != null && towerData != null)
        {
            bool success = currentSlot.PlaceTower(towerData);
            if (success)
            {
                Debug.Log("✅ 塔建造成功！");
                HideButton();
            }
            else
            {
                Debug.Log("❌ 塔建造失败！");
            }
        }
        else
        {
            if (currentSlot == null)
                Debug.Log("❌ 没有选中的槽位！");
            if (towerData == null)
                Debug.Log("❌ 没有指定塔数据！");
        }
    }
}

