// Read the path layout to understand the current map design
var tilemaps = UnityEngine.Object.FindObjectsOfType<UnityEngine.Tilemaps.Tilemap>();
UnityEngine.Tilemaps.Tilemap pathMap = null;
UnityEngine.Tilemaps.Tilemap groundMap = null;
UnityEngine.Tilemaps.Tilemap buildSlotMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "Path") pathMap = tm;
    if (tm.name == "Ground") groundMap = tm;
    if (tm.name == "BuildSlots") buildSlotMap = tm;
}

// Print path cells as a map
if (pathMap != null)
{
    var bounds = pathMap.cellBounds;
    UnityEngine.Debug.Log($"=== PATH MAP ({bounds.xMin},{bounds.yMin}) to ({bounds.xMax},{bounds.yMax}) ===");
    for (int y = bounds.yMax - 1; y >= bounds.yMin; y--)
    {
        string row = "";
        for (int x = bounds.xMin; x < bounds.xMax; x++)
        {
            var pTile = pathMap.GetTile(new UnityEngine.Vector3Int(x, y, 0));
            var bTile = buildSlotMap != null ? buildSlotMap.GetTile(new UnityEngine.Vector3Int(x, y, 0)) : null;
            if (pTile != null) row += "P";
            else if (bTile != null) row += "B";
            else row += ".";
        }
        UnityEngine.Debug.Log($"y={y:D2}: {row}");
    }
}

// Read the ground map too
var tilemaps = UnityEngine.Object.FindObjectsOfType<UnityEngine.Tilemaps.Tilemap>();
UnityEngine.Tilemaps.Tilemap groundMap = null;
UnityEngine.Tilemaps.Tilemap pathMap = null;
UnityEngine.Tilemaps.Tilemap buildSlotMap = null;
UnityEngine.Tilemaps.Tilemap decoMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "Ground") groundMap = tm;
    if (tm.name == "Path") pathMap = tm;
    if (tm.name == "BuildSlots") buildSlotMap = tm;
    if (tm.name == "Decorations") decoMap = tm;
}

var bounds = groundMap.cellBounds;
UnityEngine.Debug.Log($"=== FULL MAP ({bounds.xMin},{bounds.yMin}) to ({bounds.xMax},{bounds.yMax}) ===");
UnityEngine.Debug.Log($"G=Ground P=Path B=BuildSlot D=Deco #=overlap");
for (int y = bounds.yMax - 1; y >= bounds.yMin; y--)
{
    string row = "";
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    {
        var g = groundMap.GetTile(new UnityEngine.Vector3Int(x, y, 0));
        var p = pathMap.GetTile(new UnityEngine.Vector3Int(x, y, 0));
        var b = buildSlotMap != null ? buildSlotMap.GetTile(new UnityEngine.Vector3Int(x, y, 0)) : null;
        var d = decoMap != null ? decoMap.GetTile(new UnityEngine.Vector3Int(x, y, 0)) : null;

        if (d != null) row += "D";
        else if (p != null) row += "P";
        else if (b != null) row += "B";
        else if (g != null) row += "G";
        else row += ".";
    }
    UnityEngine.Debug.Log($"y={y:D2}: {row}");
}

