// Check camera settings and grid cell size
var cam = UnityEngine.Camera.main;
if (cam != null)
{
    UnityEngine.Debug.Log($"Main Camera: ortho={cam.orthographic}, size={cam.orthographicSize}, pos={cam.transform.position}, bg={cam.backgroundColor}");
}

var grid = UnityEngine.Object.FindObjectOfType<UnityEngine.Grid>();
if (grid != null)
{
    UnityEngine.Debug.Log($"Grid: cellSize={grid.cellSize}, cellLayout={grid.cellLayout}, transform pos={grid.transform.position} scale={grid.transform.lossyScale}");
}

// Check the actual tilemap bounds and a sample tile position
var tilemaps = UnityEngine.Object.FindObjectsOfType<UnityEngine.Tilemaps.Tilemap>();
foreach (var tm in tilemaps)
{
    var bounds = tm.cellBounds;
    var renderer = tm.GetComponent<UnityEngine.Tilemaps.TilemapRenderer>();
    UnityEngine.Debug.Log($"Tilemap '{tm.name}': bounds=({bounds.xMin},{bounds.yMin}) to ({bounds.xMax},{bounds.yMax}), " +
        $"mode={renderer?.mode}, sortOrder={renderer?.sortOrder}, orderInLayer={renderer?.sortingOrder}, " +
        $"localScale={tm.transform.localScale}");

    // Sample a tile to check world position
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    {
        for (int y = bounds.yMin; y < bounds.yMax; y++)
        {
            var tile = tm.GetTile(new UnityEngine.Vector3Int(x, y, 0));
            if (tile != null)
            {
                var worldPos = tm.CellToWorld(new UnityEngine.Vector3Int(x, y, 0));
                var localPos = tm.CellToLocal(new UnityEngine.Vector3Int(x, y, 0));
                UnityEngine.Debug.Log($"  Sample tile at ({x},{y}): local={localPos} world={worldPos}");
                goto next;
            }
        }
    }
    next:;
}

