args.script:
// Verify LevelBuilder can read Level_01 and produce correct tile counts
// Without actually painting (dry run validation)
var levelData = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_01.asset");
if (levelData == null || levelData.mapRows == null) { UnityEngine.Debug.LogError("Level_01 not found!"); return; }

int height = levelData.mapRows.Length;
int width = levelData.mapRows[0].Length;
int pathCount = 0, buildCount = 0, decoCount = 0, groundCount = 0, startCount = 0, endCount = 0;

for (int row = 0; row < height; row++)
{
    string line = levelData.mapRows[row];
    for (int col = 0; col < line.Length; col++)
    {
        char c = line[col];
        switch (c)
        {
            case 'G': groundCount++; break;
            case 'P': pathCount++; break;
            case 'B': buildCount++; break;
            case 'D': decoCount++; break;
            case 'S': startCount++; pathCount++; break;
            case 'E': endCount++; pathCount++; break;
        }
        if (c != '.') groundCount++;
    }
}

UnityEngine.Debug.Log($"Level_01 '{levelData.levelName}': {width}x{height}");
UnityEngine.Debug.Log($"  Path={pathCount} Build={buildCount} Deco={decoCount} Ground={groundCount} Start={startCount} End={endCount}");

// Validate: path should be connected from S to E
var pathCells = new System.Collections.Generic.HashSet<UnityEngine.Vector3Int>();
UnityEngine.Vector3Int? startCell = null, endCell = null;
for (int row = 0; row < height; row++)
{
    string line = levelData.mapRows[row];
    for (int col = 0; col < line.Length; col++)
    {
        char c = line[col];
        if (c == 'P' || c == 'S' || c == 'E')
        {
            var cell = new UnityEngine.Vector3Int(col, height - 1 - row, 0);
            pathCells.Add(cell);
            if (c == 'S') startCell = cell;
            if (c == 'E') endCell = cell;
        }
    }
}

if (!startCell.HasValue) UnityEngine.Debug.LogError("No start (S) found!");
if (!endCell.HasValue) UnityEngine.Debug.LogError("No end (E) found!");

// BFS from start to end
if (startCell.HasValue && endCell.HasValue)
{
    var visited = new System.Collections.Generic.HashSet<UnityEngine.Vector3Int>();
    var queue = new System.Collections.Generic.Queue<UnityEngine.Vector3Int>();
    queue.Enqueue(startCell.Value);
    visited.Add(startCell.Value);
    bool found = false;
    while (queue.Count > 0)
    {
        var cur = queue.Dequeue();
        if (cur == endCell.Value) { found = true; break; }
        foreach (var dir in new[] { UnityEngine.Vector3Int.up, UnityEngine.Vector3Int.down, UnityEngine.Vector3Int.left, UnityEngine.Vector3Int.right })
        {
            var next = cur + dir;
            if (pathCells.Contains(next) && !visited.Contains(next))
            {
                visited.Add(next);
                queue.Enqueue(next);
            }
        }
    }
    UnityEngine.Debug.Log($"  Path S->E connected: {found} (visited {visited.Count}/{pathCells.Count} path cells)");
}

