var levelData = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_01.asset");
int height = levelData.mapRows.Length;
var pathCells = new System.Collections.Generic.HashSet<UnityEngine.Vector3Int>();
UnityEngine.Vector3Int? startCell = null, endCell = null;

for (int row = 0; row < height; row++)
{
    string line = levelData.mapRows[row];
    for (int col = 0; col < line.Length; col++)
    {
        char c = line[col];
        if (c == 'P' || c == 'S' || c == 'E')
        {
            var cell = new UnityEngine.Vector3Int(col, height - 1 - row, 0);
            pathCells.Add(cell);
            if (c == 'S') startCell = cell;
            if (c == 'E') endCell = cell;
        }
    }
}

UnityEngine.Debug.Log($"Start={startCell} End={endCell} PathCells={pathCells.Count}");

if (startCell.HasValue && endCell.HasValue)
{
    var visited = new System.Collections.Generic.HashSet<UnityEngine.Vector3Int>();
    var queue = new System.Collections.Generic.Queue<UnityEngine.Vector3Int>();
    queue.Enqueue(startCell.Value);
    visited.Add(startCell.Value);
    bool found = false;
    while (queue.Count > 0)
    {
        var cur = queue.Dequeue();
        if (cur == endCell.Value) { found = true; break; }
        foreach (var dir in new[] { UnityEngine.Vector3Int.up, UnityEngine.Vector3Int.down, UnityEngine.Vector3Int.left, UnityEngine.Vector3Int.right })
        {
            var next = cur + dir;
            if (pathCells.Contains(next) && !visited.Contains(next))
            {
                visited.Add(next);
                queue.Enqueue(next);
            }
        }
    }
    UnityEngine.Debug.Log($"Path S->E connected: {found} (visited {visited.Count}/{pathCells.Count})");
}

