args.script:
var grid = UnityEngine.Object.FindObjectOfType<UnityEngine.Grid>();
var builder = grid.GetComponent<TowerDefense.Map.LevelBuilder>();
if (builder == null) builder = grid.gameObject.AddComponent<TowerDefense.Map.LevelBuilder>();

// Wire up all references
var tilemaps = grid.GetComponentsInChildren<UnityEngine.Tilemaps.Tilemap>();
UnityEngine.Tilemaps.Tilemap groundMap = null, pathMap = null, buildSlotMap = null, decoMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "Ground") groundMap = tm;
    if (tm.name == "Path") pathMap = tm;
    if (tm.name == "BuildSlots") buildSlotMap = tm;
    if (tm.name == "Decorations") decoMap = tm;
}

var so = new UnityEditor.SerializedObject(builder);
so.FindProperty("groundMap").objectReferenceValue = groundMap;
so.FindProperty("pathMap").objectReferenceValue = pathMap;
so.FindProperty("buildSlotMap").objectReferenceValue = buildSlotMap;
so.FindProperty("decorationMap").objectReferenceValue = decoMap;

var loadTile = new System.Func<string, UnityEngine.Tilemaps.TileBase>(path => 
    UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.Tilemaps.TileBase>(path));

so.FindProperty("grassTile").objectReferenceValue = loadTile("Assets/Prefabs/GrassTile.asset");
so.FindProperty("pathTile").objectReferenceValue = loadTile("Assets/Prefabs/PathTile 3.asset");
so.FindProperty("buildSlotTile").objectReferenceValue = loadTile("Assets/Prefabs/塔槽.asset");
so.FindProperty("decoStoneTile").objectReferenceValue = loadTile("Assets/Prefabs/石头.asset");
so.FindProperty("decoGrassTile1").objectReferenceValue = loadTile("Assets/Prefabs/草.asset");
so.FindProperty("decoGrassTile2").objectReferenceValue = loadTile("Assets/Prefabs/草 1.asset");
so.FindProperty("decoGrassTile3").objectReferenceValue = loadTile("Assets/Prefabs/草 2.asset");
so.FindProperty("pathHorizontalTop").objectReferenceValue = loadTile("Assets/Prefabs/横上.asset");
so.FindProperty("pathHorizontalBottom").objectReferenceValue = loadTile("Assets/Prefabs/横下.asset");
so.FindProperty("pathVerticalLeft").objectReferenceValue = loadTile("Assets/Prefabs/竖左.asset");
so.FindProperty("pathVerticalRight").objectReferenceValue = loadTile("Assets/Prefabs/竖右.asset");
so.FindProperty("pathCornerTopRight").objectReferenceValue = loadTile("Assets/Prefabs/转弯右上.asset");
so.FindProperty("pathCornerTopLeft").objectReferenceValue = loadTile("Assets/Prefabs/转弯左上.asset");
so.FindProperty("pathCornerBottomRight").objectReferenceValue = loadTile("Assets/Prefabs/转弯右下.asset");
so.FindProperty("pathCornerBottomLeft").objectReferenceValue = loadTile("Assets/Prefabs/转弯左下.asset");
so.FindProperty("towerSlotPrefab").objectReferenceValue = 
    UnityEditor.AssetDatabase.LoadAssetAtPath<UnityEngine.GameObject>("Assets/Prefabs/Towers/TowerSlot_01.prefab");

so.ApplyModifiedProperties();

// Now wire GameManager
var gm = TowerDefense.Core.GameManager.Instance;
var gmSo = new UnityEditor.SerializedObject(gm);
gmSo.FindProperty("_levelBuilder").objectReferenceValue = builder;

var level1 = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_01.asset");
var level2 = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
var level3 = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_03.asset");
var levelsProp = gmSo.FindProperty("_levels");
levelsProp.arraySize = 3;
levelsProp.GetArrayElementAtIndex(0).objectReferenceValue = level1;
levelsProp.GetArrayElementAtIndex(1).objectReferenceValue = level2;
levelsProp.GetArrayElementAtIndex(2).objectReferenceValue = level3;
gmSo.ApplyModifiedProperties();

UnityEngine.Debug.Log("All wired up successfully");

